        const reversedS = s.split('').reverse().join('');
        // parseInt handles potential leading zeros correctly (e.g., "01" becomes 1)
        return parseInt(reversedS);
    }

    /**
     * Helper function to check for primality.
     * @param {number} k 
     * @returns {boolean} True if k is prime, false otherwise.
     */
    function isPrime(k) {
        if (k <= 1) return false;
        if (k <= 3) return true;
        if (k % 2 === 0 || k % 3 === 0) return false;

        // Check divisibility up to sqrt(k) using 6k +/- 1 optimization
